import { useState } from "react";
import { motion } from "framer-motion";
import { TrendingUp, ChevronDown, ChevronUp } from "lucide-react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import DropshippingExpandedContent, { DROPSHIPPING_EXPANDED_FAQS } from "@/components/DropshippingExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 2 });
}


const FAQS = [
  { q: "How do I calculate dropshipping profit margin?", a: "Profit margin = ((Selling price - Product cost - Ad spend - Fees)  x  Selling price)  x  100. Our calculator does this automatically. A healthy margin is typically 20-40% for dropshipping." },
  { q: "What platform fees should I include?", a: "Shopify + Stripe typically charge ~2.9% + $0.30 per transaction. Shopify alone charges 0.5-2% additional if not using Shopify Payments. Enter the combined percentage in the fees field." },
  { q: "What profit margin is good for dropshipping?", a: "Anything above 20% is viable, but 30-40% is healthy. Margins below 10% leave little room for ad spend optimization or refunds. Premium or high-AOV products typically sustain better margins." },
  { q: "How do I factor in ad costs for dropshipping?", a: "Use your cost per purchase (CPP) from your ad platform - the average ad spend per converted sale. Include this in the Ad spend field. Lower CPP = higher margin." },
  { q: "Should I include shipping in the product cost?", a: "Yes. If the supplier doesn't include shipping, add it to the product cost. Free shipping offerings must be factored into your pricing to maintain margin." },
  { q: "What is a good return on ad spend (ROAS) for dropshipping?", a: "A ROAS of 2x means you earn $2 in revenue per $1 of ad spend. For dropshipping with 30% margins, you need at least 3.3x ROAS to break even. A ROAS of 4-5x is generally considered profitable for most dropshipping businesses." },
  { q: "How many sales per day do I need for a profitable dropshipping store?", a: "It depends on your margin per order. At $15 profit per order: 10 orders/day = $150/day = $4,500/month profit. At $30 profit per order: 5 orders/day = $4,500/month. Higher-ticket items require fewer daily sales to hit income targets." },
];

const EXPANDED_FAQS = DROPSHIPPING_EXPANDED_FAQS.profit;

export default function DropshippingCalculator() {
  useCurrencyVersion();
  const [productCost, setProductCost] = useState(12);
  const [sellingPrice, setSellingPrice] = useState(39.99);
  const [adSpend, setAdSpend] = useState(8);
  const [fees, setFees] = useState(3.5);

  const totalCosts = productCost + adSpend + (sellingPrice * fees) / 100;
  const profit = sellingPrice - totalCosts;
  const margin = sellingPrice > 0 ? (profit / sellingPrice) * 100 : 0;
  const roi = totalCosts > 0 ? (profit / totalCosts) * 100 : 0;
  const isProfit = profit >= 0;
  const profitPct = Math.max(0, Math.min(100, (profit / sellingPrice) * 100));
  const costPct = 100 - profitPct;

  const monthlyScenarios = [10, 30, 100, 300].map(orders => ({
    orders,
    revenue: orders * sellingPrice,
    costs: orders * totalCosts,
    profit: orders * profit,
  }));

  return (
    <>
      <SEOHead
        title="Free Dropshipping Profit Calculator Online - Instant Margins & ROI | CalcHive"
        description="Free online dropshipping profit calculator. Instantly calculate profit margins, net earnings and ROI for any dropshipping product. 100% free, no signup required, works for everyone."
        canonical="/dropshipping-profit-calculator"
        keywords="free dropshipping profit calculator, dropshipping margin calculator free online, dropshipping ROI calculator free, calculate dropshipping profit free, dropshipping earnings calculator"
        category="Dropshipping"
        faqs={EXPANDED_FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="inline-flex items-center gap-1.5 text-xs font-semibold uppercase tracking-widest text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-950/50 px-3 py-1 rounded-full mb-4">
            <TrendingUp className="w-3.5 h-3.5" /> Dropshipping
          </span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Dropshipping Profit Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free dropshipping profit calculator to calculate dropshipping profit free before you launch any product. Enter product cost, selling price, ad spend per sale, and platform fees to see your net profit per order, margin percentage, ROI, and monthly revenue projections. It works as a dropshipping margin calculator free online, a dropshipping ROI calculator free, and a dropshipping earnings calculator in one lightweight tool.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="product-cost" label="Product Cost (incl. shipping)" value={productCost} min={0.5} max={500} step={0.5} onChange={setProductCost} format={fmt} testId="input-product-cost" />
            <SliderInput id="selling-price" label="Selling Price" value={sellingPrice} min={1} max={1000} step={0.5} onChange={setSellingPrice} format={fmt} testId="input-selling-price" />
            <SliderInput id="ad-spend" label="Ad Spend per Sale (CPP)" value={adSpend} min={0} max={200} step={0.5} onChange={setAdSpend} format={fmt} testId="input-ad-spend" />
            <SliderInput id="fees" label="Platform / Transaction Fees %" value={fees} min={0} max={20} step={0.1} onChange={setFees} format={v => `${v.toFixed(1)}%`} testId="input-fees" />
          </div>
          <motion.div key={`${productCost}-${sellingPrice}-${adSpend}-${fees}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`rounded-2xl p-6 mb-4 text-center shadow-lg ${isProfit ? "bg-gradient-to-br from-emerald-500 to-emerald-700" : "bg-gradient-to-br from-red-500 to-red-700"}`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Net Profit per Sale</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-net-profit">{fmt(profit)}</p>
              <p className="text-white/70 text-sm mt-1">{margin.toFixed(1)}% margin - {roi.toFixed(0)}% ROI</p>
            </div>
            <div className="grid grid-cols-3 gap-3 mb-4">
              {[
                { label: "Selling Price", value: fmt(sellingPrice) },
                { label: "Total Costs", value: fmt(totalCosts), red: true, testId: "result-total-costs" },
                { label: "Profit Margin", value: `${margin.toFixed(1)}%`, testId: "result-margin" },
              ].map(({ label, value, red, testId }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className={`text-lg font-extrabold ${red ? "text-red-600 dark:text-red-400" : "text-foreground"}`} data-testid={testId}>{value}</p>
                </div>
              ))}
            </div>
            <div className="bg-accent/30 rounded-xl p-4">
              <p className="text-xs font-semibold text-muted-foreground mb-2">Revenue breakdown</p>
              <div className="flex rounded-full overflow-hidden h-3">
                <div className="bg-red-400 dark:bg-red-500 h-full transition-all duration-500" style={{ width: `${costPct}%` }} />
                <div className="bg-emerald-500 h-full transition-all duration-500" style={{ width: `${Math.max(0, profitPct)}%` }} />
              </div>
              <div className="flex justify-between mt-1.5 text-xs text-muted-foreground">
                <span>Costs ({costPct.toFixed(0)}%)</span>
                <span>Profit ({Math.max(0, profitPct).toFixed(0)}%)</span>
              </div>
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Calculate Your Dropshipping Profit and Margin for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Dropshipping profit is revenue minus all variable costs per order: product cost, ad spend to acquire that customer, and payment/platform fees. The result is your true net profit - what you actually keep after every cost of making that sale.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Total Costs = Product Cost + Ad Spend + (Selling Price  x  Fee%)</p>
            <p>Net Profit = Selling Price - Total Costs</p>
            <p>Margin % = (Net Profit  x  Selling Price)  x  100</p>
            <p>ROI % = (Net Profit  x  Total Costs)  x  100</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Calculate ROI for Any Dropshipping Product</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Orders/Month", "Monthly Revenue", "Monthly Costs", "Monthly Profit", "Annual Profit"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {monthlyScenarios.map(({ orders, revenue, costs, profit: p }) => (
                  <tr key={orders} className="hover:bg-muted/30">
                    <td className="py-2.5 px-3 font-semibold text-foreground">{orders}/month</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{fmt(revenue)}</td>
                    <td className="py-2.5 px-3 text-red-600 dark:text-red-400">{fmt(costs)}</td>
                    <td className={`py-2.5 px-3 font-semibold ${p >= 0 ? "text-emerald-600 dark:text-emerald-400" : "text-red-600 dark:text-red-400"}`}>{fmt(p)}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{fmt(p * 12)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Tool for Every Dropshipper</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Margin", "Assessment", "What It Means"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Below 10%", "Danger zone", "Little room for refunds, chargebacks, or ad optimization. Avoid."],
                  ["10-20%", "Tight but viable", "Requires very low ad costs. Difficult to scale profitably."],
                  ["20-30%", "Acceptable", "Industry standard. Works with optimized ad funnels."],
                  ["30-40%", "Healthy", "Good room for ad testing and occasional promotions."],
                  ["40%+", "Excellent", "Strong unit economics. Easier to scale and weather downturns."],
                ].map(([margin, assessment, meaning]) => (
                  <tr key={margin} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{margin}</td>
                    <td className="py-2.5 px-4 text-emerald-600 dark:text-emerald-400 font-medium">{assessment}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{meaning}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <DropshippingExpandedContent kind="profit" />

        <section className="mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h2>
          <div className="space-y-3">{EXPANDED_FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/dropshipping-profit-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


